(function () {
  function addStyle() { if (document.getElementById('ttv-style')) return; var s = document.createElement('style'); s.id = 'ttv-style'; s.textContent = '.ttv-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.ttv-board{position:relative;height:280px;border:1px solid #e5e7eb;border-radius:12px;background:#f8fafc;margin:12px 0}.ttv-line{position:absolute;height:3px;background:#cbd5e1;transform-origin:left center}.ttv-node{position:absolute;width:44px;height:44px;border-radius:999px;border:2px solid #007bff;background:#fff;color:#007bff;display:flex;align-items:center;justify-content:center;font-weight:700;transform:translate(-50%,-50%);transition:.25s}.ttv-node.on{background:#fff3cd;border-color:#ffc107;transform:translate(-50%,-50%) scale(1.12)}.ttv-node.done{background:#d4edda;border-color:#28a745;color:#14532d}.ttv-actions{display:flex;gap:8px;flex-wrap:wrap}.ttv-out{padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.ttvMounted) return; host.dataset.ttvMounted = '1'; addStyle(); var pts = {1:[50,14],2:[28,40],3:[72,40],4:[18,75],5:[38,75],6:[62,75],7:[82,75]}, edges = [[1,2],[1,3],[2,4],[2,5],[3,6],[3,7]], timer = 0; host.innerHTML = '<div class="ttv-wrap"><h4>🌳 Duyệt cây nhị phân</h4><div class="ttv-actions"><button type="button" data-kind="pre">Preorder</button><button type="button" data-kind="in">Inorder</button><button type="button" data-kind="post">Postorder</button></div><div class="ttv-board"></div><div class="ttv-out">Chọn kiểu duyệt.</div></div>'; var board = host.querySelector('.ttv-board'), out = host.querySelector('.ttv-out'); function line(a, b) { var p = pts[a], q = pts[b], dx = q[0] - p[0], dy = q[1] - p[1], len = Math.sqrt(dx * dx + dy * dy), d = document.createElement('div'); d.className = 'ttv-line'; d.style.left = p[0] + '%'; d.style.top = p[1] + '%'; d.style.width = len + '%'; d.style.transform = 'rotate(' + Math.atan2(dy, dx) + 'rad)'; board.appendChild(d); } function draw() { board.innerHTML = ''; edges.forEach(function (e) { line(e[0], e[1]); }); Object.keys(pts).forEach(function (k) { var n = document.createElement('div'); n.className = 'ttv-node'; n.dataset.v = k; n.style.left = pts[k][0] + '%'; n.style.top = pts[k][1] + '%'; n.textContent = k; board.appendChild(n); }); } function order(kind) { if (kind === 'pre') return [1,2,4,5,3,6,7]; if (kind === 'in') return [4,2,5,1,6,3,7]; return [4,5,2,6,7,3,1]; } function run(kind) { clearInterval(timer); draw(); var seq = order(kind), seen = [], i = 0; out.textContent = 'Đang duyệt...'; timer = setInterval(function () { if (i >= seq.length) { clearInterval(timer); out.textContent = 'Kết quả: ' + seen.join(' → '); return; } var v = seq[i], node = host.querySelector('[data-v="' + v + '"]'); node.classList.add('on'); seen.push(v); out.textContent = 'Đã thăm: ' + seen.join(' → '); setTimeout(function () { node.classList.remove('on'); node.classList.add('done'); }, 320); i++; }, 650); } host.querySelectorAll('[data-kind]').forEach(function (b) { b.addEventListener('click', function () { run(b.dataset.kind); }); }); draw(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="tree-traversal-visualizer"]').forEach(mount); });
}());
